  ('social-worker-moex-07681', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會個案工作鼻祖 Marry Richmond 以科學化的社會診斷提昇社會工作的專業化，請問其診斷的事項乃 屬於下列那一個選項？', '["問題和病理", "資源和優點", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07682', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作處遇上，社區支持體系可以發揮下列那一個功能或作用（請選出最適者）？', '["預防", "治療", "復健", "以上皆是"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07683', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下何者是老人社區日間式照顧的主要設立目的（請選最佳答案）？①讓老人適應機構照顧，加速老人', '["可提供社區居民參與照顧老人的機會", "減少照顧成本", "老人不會有被 遺棄或寂寞的感覺", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07684', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Charles Levy在S. Dillick（1984）編著《社會工作的價值基礎（Value Foundations of Social Work）》書中 的〈價值與倫理（Values and Ethics）〉一章，對社會工作實務價值分為社會價值、組織與制度價值、 專業價值和人性服務價值四大類別，其中有關「社會價值（societal values）」的指標，請問並不包括下列 那一個選項？', '["公民和法定權利", "利他主義", "自由市場競爭", "教育、健康和福祉的平等機會或管道"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07685', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '廣義的認知行為理論，乃包括Aaron Beck的認知治療、Albert Ellis的理性治療（rational therapy）或理情 治療（rational-emotive therapy）、William Glasser 的現實治療（reality therapy）和一般行為治療等理論 觀點及假定，請問其處遇的焦點或標的並不包括下列那一個選項（請選最適答案）？', '["認知或信念（belief）", "潛意識或本能驅力（drive）", "情緒", "行為"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07686', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '台灣社區發展工作發展甚早，日據時期已有類似英國睦鄰運動的「鄰保事業」，嗣後聯合國社區發展工 作正式引進啟動台灣以「社區」為名的相關計畫，至於對基層的社區組織的型態，則隨著發展過程的變 遷而有所不同，請問現行的基層社區組織單位，係以何種方式運作？', '["社會運動方式", "人民團體方式", "志願組織方式", "社區營造方式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07687', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作有三項基本功能，重建、提供服務及預防，彼此互相連結並互相依存。假設：社區的服務委員 會，運用社區組織與社會資源，並僱用專業人員，幫助接近犯罪邊緣或住在犯罪區的少年，請問，其所 提供的服務係屬於那一種社會工作基本功能？', '["重建", "矯治", "預防", "治療"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07688', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的督導方式，已有所改變，不再是以前那樣上對下僵化的督導，一般趨勢是採用自我指導方式， 而較少採用拘泥的督導與被督導的關係，目前較廣泛使用的方式，除參與式督導、自我督導之外，尚有 何種型式的督導？', '["行政督導", "專家督導", "同儕督導", "團體督導"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07689', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以社區工作方法與技術而言，請問社區工作的主要技術為何？', '["調查", "傾聽", "同理", "方案規劃"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
